// API 接受 HTMLElement,不要传 id；生成的 SVG 与指针监听会留在 shadow 容器
import HanziWriter from 'https://cdn.jsdelivr.net/npm/hanzi-writer@3/+esm';
const el = document.createElement('div'); el.style.cssText = 'width:300px;height:300px'; shadowRoot.appendChild(el);
const writer = HanziWriter.create(el, data.character, { width: 300, height: 300, showOutline: data.showOutline ?? true, strokeAnimationSpeed: data.strokeAnimationSpeed ?? 1 });
if ((data.action ?? 'animate') === 'quiz') writer.quiz();
else if ((data.action ?? 'animate') === 'animate') writer.animateCharacter();
